/* eslint-disable @typescript-eslint/no-non-null-assertion */
import { isUndefined } from 'lodash-es';
import { forwardRef, type MouseEvent as ReactMouseEvent } from 'react';

import { Divider } from '../../../../../../layouts/divider/Divider.js';
import { Flex } from '../../../../../../layouts/flex/Flex.js';
import type { TruncationMode } from '../../../../../../typography/text-ellipsis/TextEllipsis.js';
import { TooltipItem, SeriesDisplayMode } from '../../../../types/tooltip.js';
import { MultiDataPointShape } from '../../../shape/MultiDataPointShape.js';
import { SingleDataPointShape } from '../../../shape/SingleDataPointShape.js';
import {
  valueContainer,
  valueItem,
  detailViewContent,
  detailViewItem,
} from '../../shared/styles/SeriesBasedContent.sty.js';
import { SeriesName } from '../components/SeriesName.js';
import { useInteractiveTooltip } from '../hooks/useInteractiveTooltip.js';

export interface SeriesBasedContentProps {
  /** The item for this entry */
  item: TooltipItem;
  /** Indicates if the item needs to be highlighted */
  highlighted?: boolean;
  /** Indicates if the item needs a divider on the bottom */
  showDivider?: boolean;
  /** The series display mode */
  seriesDisplayMode?: SeriesDisplayMode;
  /** The series display mode */
  nameFormatter?: (item: TooltipItem) => string;
  onMouseHover?: (event: ReactMouseEvent) => void;
  truncationMode?: TruncationMode;
  isScrolling?: boolean;
}

export const SeriesBasedContent = forwardRef<
  HTMLButtonElement,
  SeriesBasedContentProps
>((props, ref) => {
  const {
    item,
    seriesDisplayMode = 'single-line',
    highlighted = false,
    showDivider = false,
    nameFormatter,
    onMouseHover,
    truncationMode,
    isScrolling,
    ...remaining
  } = props;
  const { selectItem } = useInteractiveTooltip();
  const dimensionNames = Array.isArray(item.name) ? item.name : [item.name];

  const isOnlyOneDimension =
    !Array.isArray(item.name) || item.name.length === 1;

  const singleLine = seriesDisplayMode === 'single-line' || isOnlyOneDimension;
  const handleMouseHover = (e: ReactMouseEvent) => {
    selectItem?.(e, item);
    onMouseHover?.(e);
  };

  const colorIndicator = singleLine ? (
    <SingleDataPointShape color={item.color!.Default} active={highlighted} />
  ) : (
    <MultiDataPointShape color={item.color!.Default} active={highlighted} />
  );

  return (
    <button
      className={detailViewContent}
      ref={ref}
      onMouseEnter={handleMouseHover}
      {...remaining}
    >
      <div className={detailViewItem}>
        {!isUndefined(item.color) && colorIndicator}

        <SeriesName
          names={dimensionNames}
          item={item}
          nameFormatter={nameFormatter}
          highlighted={highlighted}
          singleLine={singleLine}
          truncationMode={truncationMode}
          isScrolling={isScrolling}
        />

        <span className={valueContainer} role="grid">
          <Flex gap={4} alignItems="center" role="row">
            {item.values!.length > 1 && (
              <span className={valueItem} role="cell">
                {item.values![1]}
              </span>
            )}
            <span className={valueItem} role="cell">
              {item.values![0]}
            </span>
          </Flex>
        </span>
      </div>
      {showDivider && <Divider />}
    </button>
  );
});

(
  SeriesBasedContent as typeof SeriesBasedContent & { displayName: string }
).displayName = 'SeriesBasedContent';
